\begin{tabular}{|l|l|l|l|}
\hline 4 & 2 & 3 & 2 \\
\hline 3 & 3 & 1 & 2 \\
\hline 2 & 1 & 3 & 1 \\
\hline 1 & 2 & 1 & 2 \\
\hline \multicolumn{4}{|c|}{الواجهة}
\end{tabular}

